function scanToolRecommendations(ai,techStack){
  const a=[...ai];
  const u=(...p)=>p.some(x=>a.some(imp=>imp===x||imp.startsWith(x+'/')));
  const pkg=readJSON('package.json')??{};
  const deps={...pkg.dependencies,...pkg.devDependencies};
  const installed=n=>!!deps[n];
  const aj=readJSON('app.json')?.expo??{};
  const recs=[];

  // FlashList - installed but not imported
  if(installed('@shopify/flash-list')&&!u('@shopify/flash-list')){
    recs.push({name:'@shopify/flash-list',priority:'medium',status:'installed-unused',
      why:'FlashList is installed but never imported anywhere in your source code.',
      where:'Replace FlatList usages with FlashList. Search for <FlatList and replace.',
      install:'already installed',
      usage:'import {FlashList} from "@shopify/flash-list";'});
  } else if(!installed('@shopify/flash-list')&&!u('@shopify/flash-list')){
    recs.push({name:'@shopify/flash-list',priority:'high',status:'missing',
      why:'You use FlatList which is slow for large lists. FlashList is 5-10x faster with recycling.',
      where:'Replace every <FlatList with <FlashList. Add estimatedItemSize prop.',
      install:'npm install @shopify/flash-list',
      usage:'import {FlashList} from "@shopify/flash-list"; <FlashList data={data} estimatedItemSize={80} renderItem={renderItem} keyExtractor={k=>k.id}/>'});
  }

  // TanStack Query
  const fetchCount=(readFile('package.json')||'').includes('@tanstack/react-query');
  if(!u('@tanstack/react-query')&&!installed('@tanstack/react-query')){
    const fc=getSourceData().reduce((a,d)=>(a+(d.stripped.match(/\bfetch\s*\(/g)||[]).length),0);
    if(fc>10){
      recs.push({name:'@tanstack/react-query',priority:'medium',status:'missing',
        why:`You have ${fc} fetch() calls managed with useState+useEffect. This pattern causes race conditions, memory leaks, and duplicate requests.`,
        where:'Replace all fetch+useState+useEffect patterns. Especially for Firebase reads, API calls, any server data.',
        install:'npm install @tanstack/react-query',
        usage:'const {data,isLoading,error}=useQuery({queryKey:["key"],queryFn:fetchFn,staleTime:1000*60*5});'});
    }
  }

  // React Compiler
  if(!aj.experiments?.reactCompiler){
    const sdkV=parseInt(aj.sdkVersion||'0',10);
    if(sdkV>=54||!aj.sdkVersion){
      recs.push({name:'React Compiler (reactCompiler: true)',priority:'medium',status:'not-configured',
        why:'Without React Compiler you must manually add useMemo/useCallback everywhere. The compiler adds them automatically where safe.',
        where:'app.json experiments section. Affects all components automatically - no code changes needed.',
        install:'no install needed on SDK 54+ - one line in app.json',
        usage:'{"expo":{"experiments":{"reactCompiler":true}}}'});
    }
  }

  // Metro inlineRequires
  const mc=readFile('metro.config.js')||'';
  if(!mc.includes('inlineRequires')){
    recs.push({name:'metro inlineRequires',priority:'low',status:'not-configured',
      why:'Modules load at startup even if never used. inlineRequires defers loading until first call, reducing cold start time.',
      where:'metro.config.js transformer section.',
      install:'no install needed',
      usage:'config.transformer={...config.transformer,inlineRequires:true};'});
  }

  // Sentry
  if(!u('@sentry/react-native')&&!installed('@sentry/react-native')){
    recs.push({name:'@sentry/react-native',priority:'high',status:'missing',
      why:'No crash reporting. When your app crashes in production you have no way to know what went wrong.',
      where:'Initialize in app/_layout.tsx before anything else. Wrap root with Sentry.wrap().',
      install:'npm install @sentry/react-native && npx @sentry/wizard@latest -i reactNative',
      usage:'Sentry.init({dsn:process.env.EXPO_PUBLIC_SENTRY_DSN});'});
  }

  // react-native-mmkv
  if(!u('react-native-mmkv')&&!installed('react-native-mmkv')){
    if(u('@react-native-async-storage/async-storage')||has('AsyncStorage')){
      recs.push({name:'react-native-mmkv',priority:'medium',status:'missing',
        why:'AsyncStorage is async and slow. MMKV is synchronous and ~30x faster. No await needed.',
        where:'Replace AsyncStorage calls in storage utils, auth token storage, user preferences.',
        install:'npm install react-native-mmkv',
        usage:'import {createMMKV} from "react-native-mmkv"; const storage=createMMKV();'});
    }
  }

  // Reanimated
  if(!u('react-native-reanimated')&&!installed('react-native-reanimated')){
    recs.push({name:'react-native-reanimated',priority:'low',status:'missing',
      why:'Animations using Animated API run on JS thread and jank when JS is busy. Reanimated runs on UI thread.',
      where:'Replace Animated.View with Animated from reanimated for any gesture-driven or continuous animations.',
      install:'npm install react-native-reanimated react-native-worklets',
      usage:'import Animated,{useSharedValue,useAnimatedStyle,withSpring} from "react-native-reanimated";'});
  }

  // Prettier
  const hasPrettier=fileExists('.prettierrc')||fileExists('.prettierrc.json')||fileExists('.prettierrc.js')||fileExists('prettier.config.js')||(readJSON('package.json')?.prettier);
  if(!hasPrettier){
    recs.push({name:'prettier',priority:'low',status:'missing',
      why:'No code formatter. Code style is inconsistent across files.',
      where:'Root of project. Add format script to package.json.',
      install:'npm install --save-dev prettier',
      usage:'echo {}>.prettierrc && npx prettier --write "**/*.{ts,tsx}"'});
  }

  const high=recs.filter(r=>r.priority==='high').length;
  const medium=recs.filter(r=>r.priority==='medium').length;
  const low=recs.filter(r=>r.priority==='low').length;
  return{recs,counts:{high,medium,low}};
}

// ─── FILE COMPACTNESS ───
function scanCompactness(){
  const issues=[];
  const SKIP_COMMENT_CHECK=new Set(['safety','detector','predator','grooming','nsfw','moderation','child','trafficking']);
  for(const{rel:rp,content,lines}of getSourceData()){
    if(rp.includes('node_modules'))continue;
    const total=lines.length;
    if(total<5)continue;
    const isSafetyFile=SKIP_COMMENT_CHECK.has(path.basename(rp,path.extname(rp)).toLowerCase())||
      SKIP_COMMENT_CHECK.has(rp.split(path.sep).slice(-2,-1)[0]||'');
    const blankLines=lines.filter(l=>!l.trim()).length;
    const commentLines=lines.filter(l=>{const s=l.trim();return s.startsWith('//')||s.startsWith('*')||s.startsWith('/*')||s.startsWith('* ')}).length;
    const blankPct=blankLines/total;
    const commentPct=commentLines/total;
    const fileIssues=[];
    if(blankPct>0.2)fileIssues.push(`${Math.round(blankPct*100)}% blank lines (${blankLines}/${total}) - remove excess whitespace`);
    if(!isSafetyFile&&commentPct>0.25)fileIssues.push(`${Math.round(commentPct*100)}% comment lines (${commentLines}/${total}) - remove comments, code should be self-explanatory`);
    if(fileIssues.length)issues.push({file:rp,lines:total,issues:fileIssues,sample:lines.find(l=>l.trim().startsWith('//'))||''});
  }
  issues.sort((a,b)=>{
    const scoreA=(a.issues.join('').includes('comment')?2:0)+(a.issues.join('').includes('blank')?1:0);
    const scoreB=(b.issues.join('').includes('comment')?2:0)+(b.issues.join('').includes('blank')?1:0);
    return scoreB-scoreA;
  });
  return{total:issues.length,issues:issues.slice(0,30)};
}

// ─── COMMENTS SCAN ───
function scanComments(){
  const SAFETY_KEYWORDS=['safety','detector','predator','grooming','nsfw','moderation','child','trafficking','childSafety','predatorDetection'];
  let totalLines=0,inlineCount=0,blockCount=0,jsdocCount=0;
  const fileIssues=[];
  for(const{rel:rp,content,lines}of getSourceData()){
    const isSafetyFile=SAFETY_KEYWORDS.some(k=>rp.toLowerCase().includes(k));
    let fileComments=0;
    const samples=[];
    for(const l of lines){
      const s=l.trim();
      if(s.startsWith('/**')){jsdocCount++;fileComments++;if(samples.length<2)samples.push(s)}
      else if(s.startsWith('/*')){blockCount++;fileComments++;if(samples.length<2)samples.push(s)}
      else if(s.startsWith('//')){inlineCount++;fileComments++;if(samples.length<2)samples.push(s)}
    }
    totalLines+=fileComments;
    if(!isSafetyFile&&fileComments>8){
      fileIssues.push({file:rp,count:fileComments,samples:samples.slice(0,2)});
    }
  }
  fileIssues.sort((a,b)=>b.count-a.count);
  return{totalLines,inlineCount,blockCount,jsdocCount,filesWithManyComments:fileIssues.length,fileIssues:fileIssues.slice(0,20)};
}

